out.println("<div>" + description + "</div>");
// If description = <script>alert(1)</script>
// HTML: <div><script>alert(1)</script></div>
// Browser EXECUTES the script!

// SECURE CODE:
String description = database.getProfile(userId);
String encoded = description
    .replace("&", "&amp;")
    .replace("<", "&lt;")
    .replace(">", "&gt;")
    .replace("\"", "&quot;")
    .replace("'", "&#x27;");
out.println("<div>" + encoded + "</div>");
// If description = <script>alert(1)</script>
// HTML: <div>&lt;script&gt;alert(1)&lt;/script&gt;</div>
// Browser displays it as TEXT. Script NEVER executes.

// EVEN BETTER — use a library:
import org.owasp.encoder.Encode;
out.println("<div>" + Encode.forHtml(description) + "</div>");
// OWASP Encoder handles ALL edge cases automatically.

// VULNERABLE COOKIE SETUP (Java):
Cookie session = new Cookie("JSESSIONID", sessionId);
response.addCookie(session);
// document.cookie RETURNS the session ID
// Cookie sent over HTTP (can be intercepted)

// SECURE COOKIE SETUP:
Cookie session = new Cookie("JSESSIONID", sessionId);
session.setHttpOnly(true);   // JavaScript CANNOT read it
session.setSecure(true);     // Only sent over HTTPS
session.setMaxAge(1800);     // Expires in 30 minutes
response.addCookie(session);

// With SameSite (requires Servlet 6.0+ or header):
response.setHeader("Set-Cookie",
    "JSESSIONID=" + sessionId +
    "; HttpOnly; Secure; SameSite=Strict; Path=/");

// TEST:
// document.cookie now returns '' (empty)
// XSS payload: alert(document.cookie) shows nothing useful
// Cookie NOT sent with cross-site requests (SameSite=Strict)
// Chain broken: XSS exists but CANNOT steal the session!

