// SERVER-SIDE VALIDATION:
String submittedToken = request.getParameter("csrf_token");
String sessionToken = (String) session.getAttribute("csrf_token");
if (submittedToken == null || !submittedToken.equals(sessionToken)) {
    response.sendError(403, "Invalid CSRF token");
    return;  // REJECT the request!
}
// XHR from XSS does NOT know the token value
// → transfer REJECTED → funds safe!

// WITHOUT CSP — browser executes ANY script:
// <script>alert('XSS')</script> → EXECUTES
// <img onerror="alert(1)"> → EXECUTES
// <div onmouseover="alert(1)"> → EXECUTES

// WITH CSP — browser blocks inline scripts:
// Server sends this header:
// Content-Security-Policy: script-src 'self'

// Now:
// <script>alert('XSS')</script> → BLOCKED
// <img onerror="alert(1)"> → BLOCKED
// <div onmouseover="alert(1)"> → BLOCKED
// <script src="/js/app.js"></script> → ALLOWED (same origin)

// IN JAVA SERVLET:
response.setHeader("Content-Security-Policy",
    "script-src 'self'; " +      // Only scripts from our domain
    "style-src 'self'; " +        // Only styles from our domain
    "img-src 'self' data:; " +    // Images from our domain + data URIs
    "default-src 'self'; " +      // Everything else: our domain only
    "report-uri /csp-report");    // Log violations

// CSP is the nuclear option against XSS:
// Even if a script gets injected into the HTML,
// the BROWSER refuses to execute it.
// The entire worm is dead before it starts.

